import { Component, OnInit } from '@angular/core';
import { CommonModule } from '@angular/common';
import { ReactiveFormsModule, FormBuilder, FormGroup, Validators } from '@angular/forms';

interface InvoiceRecord {
  id: string;
  patientName: string;
  labName: string;
  wardNumber: string;
  doctorName: string;
  treatment: string;
  totalAmount: number;
}

@Component({
  selector: 'app-invoice',
  standalone: true,
  imports: [CommonModule, ReactiveFormsModule],
  templateUrl: './invoice.component.html',
  styleUrls: ['./invoice.component.scss']
})
export class InvoiceComponent implements OnInit {
  invoiceForm!: FormGroup;
  totalAmount: number = 15000; // القيمة الافتراضية الظاهرة بالصورة

  // قائمة الفواتير الأخيرة المطابقة للجدول بالصورة
  invoiceList: InvoiceRecord[] = [
    { id: '1', patientName: 'Naveed', labName: 'Blood test', wardNumber: '1', doctorName: 'Dr.Asanka', treatment: 'Dengue', totalAmount: 15000.00 },
    { id: '2', patientName: 'Jayani', labName: 'Blood test', wardNumber: '1', doctorName: 'Dr.Asanka', treatment: 'Dengue', totalAmount: 15000.00 },
    { id: '3', patientName: 'Jayani', labName: 'Blood test', wardNumber: '1', doctorName: 'Dr.Asanka', treatment: 'Dengue', totalAmount: 15000.00 },
    { id: '4', patientName: 'Jayani', labName: 'Blood test', wardNumber: '1', doctorName: 'Dr.Asanka', treatment: 'Dengue', totalAmount: 15000.00 }
  ];

  constructor(private fb: FormBuilder) {}

  ngOnInit(): void {
    this.initForm();
  }

  initForm(): void {
    this.invoiceForm = this.fb.group({
      patientName: ['Naveed', Validators.required],
      doctorName: ['Dr.Asanka', Validators.required],
      labName: ['Blood test', Validators.required],
      treatment: ['Dengue', Validators.required],
      wardNumber: ['1', Validators.required]
    });
  }

  onGenerateBill(): void {
    if (this.invoiceForm.valid) {
      const newInvoice: InvoiceRecord = {
        id: (this.invoiceList.length + 1).toString(),
        ...this.invoiceForm.value,
        totalAmount: this.totalAmount
      };
      this.invoiceList.push(newInvoice);
    } else {
      this.invoiceForm.markAllAsTouched();
    }
  }

  onSearch(id: string): void {
    const inv = this.invoiceList.find(i => i.id === id);
    if (inv) {
      this.invoiceForm.patchValue(inv);
    } else {
      alert('Invoice ID not found');
    }
  }
}
